{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_squared_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// IVF parameters
const DIM: usize = 128;
const N_CLUSTERS: usize = 1024;   // number of IVF centroids
const N_PROBE: usize = 48;        // number of clusters to probe at search time

/// Wrapper for ordered f32 (max-heap by distance — keeps k smallest)
#[derive(Clone, Copy)]
struct DistId(f32, u64);

impl PartialEq for DistId {
    fn eq(&self, other: &Self) -> bool { self.0 == other.0 }
}
impl Eq for DistId {}
impl PartialOrd for DistId {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.0.partial_cmp(&other.0)
    }
}
impl Ord for DistId {
    fn cmp(&self, other: &Self) -> Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(Ordering::Equal)
    }
}

pub struct VectorDB {
    inner: RwLock<DBInner>,
}

struct DBInner {
    /// Flat storage: all vectors stored contiguously, indexed by position
    vectors: Vec<f32>,   // len = n_vectors * DIM
    ids: Vec<u64>,       // len = n_vectors

    /// IVF index
    /// centroids[c*DIM..(c+1)*DIM] = centroid c
    centroids: Vec<f32>,      // N_CLUSTERS * DIM
    /// For each cluster c: sorted list of vector indices
    clusters: Vec<Vec<u32>>,  // N_CLUSTERS entries

    /// Number of vectors when IVF was last built
    index_built_at: usize,
    /// Flag: do we have a valid IVF index?
    index_valid: bool,
}

impl DBInner {
    fn new() -> Self {
        DBInner {
            vectors: Vec::new(),
            ids: Vec::new(),
            centroids: Vec::new(),
            clusters: vec![Vec::new(); N_CLUSTERS],
            index_built_at: 0,
            index_valid: false,
        }
    }

    #[inline(always)]
    fn n_vectors(&self) -> usize {
        self.ids.len()
    }

    #[inline(always)]
    fn get_vector(&self, idx: usize) -> &[f32] {
        &self.vectors[idx * DIM..(idx + 1) * DIM]
    }

    /// Build IVF index using k-means
    fn build_index(&mut self) {
        let n = self.n_vectors();
        if n < N_CLUSTERS {
            self.index_valid = false;
            return;
        }

        eprintln!("Building IVF index for {} vectors...", n);

        // Initialize centroids by sampling evenly
        let step = n / N_CLUSTERS;
        let mut centroids = vec![0.0f32; N_CLUSTERS * DIM];
        for c in 0..N_CLUSTERS {
            let src = self.get_vector(c * step);
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(src);
        }

        // K-means iterations
        let n_iters = 20;
        let mut assignments = vec![0u32; n];

        for iter in 0..n_iters {
            // Assignment step (parallel)
            let vectors_ref = &self.vectors;
            let centroids_ref = &centroids;

            let new_assignments: Vec<u32> = (0..n).into_par_iter().map(|i| {
                let v = &vectors_ref[i * DIM..(i + 1) * DIM];
                let mut best_c = 0u32;
                let mut best_dist = f32::MAX;
                for c in 0..N_CLUSTERS {
                    let cv = &centroids_ref[c * DIM..(c + 1) * DIM];
                    let d = l2_squared_f32(v, cv);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c as u32;
                    }
                }
                best_c
            }).collect();

            let changed = new_assignments.iter().zip(assignments.iter())
                .filter(|(a, b)| a != b).count();
            assignments = new_assignments;

            // Update centroids
            let mut counts = vec![0u32; N_CLUSTERS];
            let mut new_centroids = vec![0.0f32; N_CLUSTERS * DIM];

            for i in 0..n {
                let c = assignments[i] as usize;
                counts[c] += 1;
                let v = &self.vectors[i * DIM..(i + 1) * DIM];
                let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                for d in 0..DIM {
                    cv[d] += v[d];
                }
            }

            for c in 0..N_CLUSTERS {
                let cnt = counts[c];
                if cnt > 0 {
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cv[d] /= cnt as f32;
                    }
                } else {
                    // keep old centroid
                    new_centroids[c * DIM..(c + 1) * DIM]
                        .copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                }
            }

            centroids = new_centroids;

            eprintln!("  k-means iter {}: {} changed", iter, changed);
            if changed == 0 {
                break;
            }
        }

        // Build inverted lists
        let mut clusters: Vec<Vec<u32>> = vec![Vec::new(); N_CLUSTERS];
        for i in 0..n {
            clusters[assignments[i] as usize].push(i as u32);
        }

        self.centroids = centroids;
        self.clusters = clusters;
        self.index_built_at = n;
        self.index_valid = true;
        eprintln!("IVF index built.");
    }

    /// Assign a single vector to its nearest centroid and add to that cluster
    fn add_to_index(&mut self, idx: usize) {
        if !self.index_valid || self.centroids.is_empty() {
            return;
        }
        let v = &self.vectors[idx * DIM..(idx + 1) * DIM];
        let mut best_c = 0usize;
        let mut best_dist = f32::MAX;
        for c in 0..N_CLUSTERS {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            let d = l2_squared_f32(v, cv);
            if d < best_dist {
                best_dist = d;
                best_c = c;
            }
        }
        self.clusters[best_c].push(idx as u32);
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n_probe = N_PROBE.min(N_CLUSTERS);

        // Compute distances to all centroids
        let mut centroid_dists: Vec<(f32, usize)> = (0..N_CLUSTERS).map(|c| {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            (l2_squared_f32(query, cv), c)
        }).collect();

        // Partial sort to get top n_probe cheapest centroids
        centroid_dists.select_nth_unstable_by(n_probe - 1, |a, b| {
            a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal)
        });

        // Search within probed clusters
        // Use a max-heap of size top_k to track k-nearest
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for &(_, c) in &centroid_dists[..n_probe] {
            for &vi in &self.clusters[c] {
                let v = self.get_vector(vi as usize);
                let d = l2_squared_f32(query, v);
                if heap.len() < top_k {
                    heap.push(DistId(d, self.ids[vi as usize]));
                    if heap.len() == top_k {
                        worst = heap.peek().unwrap().0;
                    }
                } else if d < worst {
                    heap.pop();
                    heap.push(DistId(d, self.ids[vi as usize]));
                    worst = heap.peek().unwrap().0;
                }
            }
        }

        // BinaryHeap is a max-heap. into_sorted_vec() gives ascending order.
        let results: Vec<SearchResult> = heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect();
        results
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n = self.n_vectors();
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for i in 0..n {
            let v = self.get_vector(i);
            let d = l2_squared_f32(query, v);
            if heap.len() < top_k {
                heap.push(DistId(d, self.ids[i]));
                if heap.len() == top_k {
                    worst = heap.peek().unwrap().0;
                }
            } else if d < worst {
                heap.pop();
                heap.push(DistId(d, self.ids[i]));
                worst = heap.peek().unwrap().0;
            }
        }

        // into_sorted_vec gives ascending order for max-heap
        let results: Vec<SearchResult> = heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect();
        results
    }
}

impl VectorDB {
    pub fn new() -> Self {
        // Configure rayon to use 4 threads (matching our pinned CPU allocation)
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            inner: RwLock::new(DBInner::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut db = self.inner.write();
        let idx = db.n_vectors();
        db.ids.push(id);
        db.vectors.extend_from_slice(&vector);
        db.add_to_index(idx);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut db = self.inner.write();
            let start_idx = db.n_vectors();

            db.ids.reserve(count);
            db.vectors.reserve(count * DIM);

            for (id, vec) in &vectors {
                db.ids.push(*id);
                db.vectors.extend_from_slice(vec);
            }

            // If index is valid, add new vectors to existing index
            if db.index_valid {
                for i in 0..count {
                    db.add_to_index(start_idx + i);
                }
            }
        }

        // Trigger index build when appropriate
        {
            let should_build = {
                let db = self.inner.read();
                let n = db.n_vectors();
                let built_at = db.index_built_at;
                let valid = db.index_valid;
                n >= N_CLUSTERS && (!valid || built_at < n / 2)
            };

            if should_build {
                let mut db = self.inner.write();
                let n = db.n_vectors();
                let built_at = db.index_built_at;
                let valid = db.index_valid;
                if n >= N_CLUSTERS && (!valid || built_at < n / 2) {
                    db.build_index();
                }
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let db = self.inner.read();
        let top_k = top_k as usize;

        if db.index_valid && db.n_vectors() >= N_CLUSTERS {
            db.search_ivf(vector, top_k)
        } else {
            db.search_brute_force(vector, top_k)
        }
    }
}
