    /// Number of vectors when IVF was last built
    index_built_at: usize,
    index_valid: bool,
}

impl DBInner {
    fn new() -> Self {
        DBInner {
            vectors: Vec::new(),
            ids: Vec::new(),
            centroids: Vec::new(),
            clusters: vec![Vec::new(); N_CLUSTERS],
            index_built_at: 0,
            index_valid: false,
        }
    }

    #[inline(always)]
    fn n_vectors(&self) -> usize {
        self.ids.len()
    }

    #[inline(always)]
    fn get_vector(&self, idx: usize) -> &[f32] {
        &self.vectors[idx * DIM..(idx + 1) * DIM]
    }

    /// Build IVF index using k-means (parallel, optimized)
    fn build_index(&mut self) {
        let n = self.n_vectors();
        if n < N_CLUSTERS {
            self.index_valid = false;
            return;
        }

        eprintln!("Building IVF index for {} vectors, {} clusters...", n, N_CLUSTERS);

        // Initialize centroids by sampling evenly spaced
        let step = n / N_CLUSTERS;
        let mut centroids = vec![0.0f32; N_CLUSTERS * DIM];
        for c in 0..N_CLUSTERS {
            let src = self.get_vector(c * step);
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(src);
        }

        let n_iters = 10;
        let mut assignments = vec![0u32; n];

        for iter in 0..n_iters {
            let vectors_ref = &self.vectors;
            let centroids_ref = &centroids;

            // Parallel assignment
            let new_assignments: Vec<u32> = (0..n).into_par_iter().map(|i| {
                let v = &vectors_ref[i * DIM..(i + 1) * DIM];
                let mut best_c = 0u32;
                let mut best_dist = f32::MAX;
                for c in 0..N_CLUSTERS {
                    let cv = &centroids_ref[c * DIM..(c + 1) * DIM];
                    let d = l2_squared_f32(v, cv);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c as u32;
                    }
                }
                best_c
            }).collect();

            let changed = new_assignments.iter().zip(assignments.iter())
                .filter(|(a, b)| a != b).count();
            assignments = new_assignments;

            // Parallel centroid update using reduce
            // Split into chunks for parallel accumulation
            let n_threads = 4;
            let chunk_size = (n + n_threads - 1) / n_threads;

            let partial: Vec<(Vec<f32>, Vec<u32>)> = (0..n_threads).into_par_iter().map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                if start >= end {
                    return (vec![0.0f32; N_CLUSTERS * DIM], vec![0u32; N_CLUSTERS]);
                }
                let mut sums = vec![0.0f32; N_CLUSTERS * DIM];
                let mut counts = vec![0u32; N_CLUSTERS];
                for i in start..end {
                    let c = assignments[i] as usize;
                    counts[c] += 1;
                    let v = &vectors_ref[i * DIM..(i + 1) * DIM];
                    let cv = &mut sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cv[d] += v[d];
                    }
                }
                (sums, counts)
            }).collect();

            // Merge partial sums
            let mut new_centroids = vec![0.0f32; N_CLUSTERS * DIM];
            let mut counts = vec![0u32; N_CLUSTERS];
            for (sums, cnts) in &partial {
                for c in 0..N_CLUSTERS {
                    counts[c] += cnts[c];
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    let sv = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cv[d] += sv[d];
                    }
                }
            }

            for c in 0..N_CLUSTERS {
                let cnt = counts[c];
                if cnt > 0 {
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    let inv = 1.0f32 / cnt as f32;
                    for d in 0..DIM {
                        cv[d] *= inv;
                    }
                } else {
                    // keep old centroid
                    new_centroids[c * DIM..(c + 1) * DIM]
                        .copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                }
            }

            centroids = new_centroids;
            eprintln!("  k-means iter {}: {} changed", iter, changed);
            if changed == 0 {
                break;
            }
        }

        // Build inverted lists
        let mut clusters: Vec<Vec<u32>> = vec![Vec::new(); N_CLUSTERS];
        for i in 0..n {
            clusters[assignments[i] as usize].push(i as u32);
        }

        self.centroids = centroids;
        self.clusters = clusters;
        self.index_built_at = n;
        self.index_valid = true;
        eprintln!("IVF index built.");
    }

    fn add_to_index(&mut self, idx: usize) {
        if !self.index_valid || self.centroids.is_empty() {
            return;
        }
        let v = &self.vectors[idx * DIM..(idx + 1) * DIM];
        let mut best_c = 0usize;
        let mut best_dist = f32::MAX;
        for c in 0..N_CLUSTERS {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            let d = l2_squared_f32(v, cv);
            if d < best_dist {
                best_dist = d;
                best_c = c;
            }
        }
        self.clusters[best_c].push(idx as u32);
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n_probe = N_PROBE.min(N_CLUSTERS);

        // Compute distances to all centroids
        let mut centroid_dists: Vec<(f32, usize)> = (0..N_CLUSTERS).map(|c| {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            (l2_squared_f32(query, cv), c)
        }).collect();

        // Partial sort to get top n_probe
        centroid_dists.select_nth_unstable_by(n_probe - 1, |a, b| {
            a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal)
        });

        // Search within probed clusters using max-heap
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for &(_, c) in &centroid_dists[..n_probe] {
            for &vi in &self.clusters[c] {
                let v = self.get_vector(vi as usize);
                let d = l2_squared_f32(query, v);
                if heap.len() < top_k {
                    heap.push(DistId(d, self.ids[vi as usize]));
                    if heap.len() == top_k {
                        worst = heap.peek().unwrap().0;
                    }
                } else if d < worst {
                    heap.pop();
                    heap.push(DistId(d, self.ids[vi as usize]));
                    worst = heap.peek().unwrap().0;
                }
            }
        }

        // into_sorted_vec gives ascending order for max-heap (smallest first)
        heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n = self.n_vectors();
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for i in 0..n {
            let v = self.get_vector(i);
            let d = l2_squared_f32(query, v);
            if heap.len() < top_k {
                heap.push(DistId(d, self.ids[i]));
                if heap.len() == top_k {
                    worst = heap.peek().unwrap().0;
                }
            } else if d < worst {
                heap.pop();
                heap.push(DistId(d, self.ids[i]));
                worst = heap.peek().unwrap().0;
            }
        }

        heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }
}

