            db.ids.reserve(count);
            db.vectors.reserve(count * DIM);

            for (id, vec) in &vectors {
                db.ids.push(*id);
                db.vectors.extend_from_slice(vec);
            }

            if db.index_valid {
                for i in 0..count {
                    db.add_to_index(start_idx + i);
                }
            }
        }

        // Trigger index build when needed
        let should_build = {
            let db = self.inner.read();
            let n = db.n_vectors();
            let built_at = db.index_built_at;
            let valid = db.index_valid;
            n >= N_CLUSTERS && (!valid || built_at < n / 2)
        };

        if should_build {
            let mut db = self.inner.write();
            let n = db.n_vectors();
            let built_at = db.index_built_at;
            let valid = db.index_valid;
            if n >= N_CLUSTERS && (!valid || built_at < n / 2) {
                db.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let db = self.inner.read();
        let top_k = top_k as usize;

        if db.index_valid && db.n_vectors() >= N_CLUSTERS {
            db.search_ivf(vector, top_k)
        } else {
            db.search_brute_force(vector, top_k)
        }
    }
}
