            let centroids_ref = &centroids;

            // Parallel assignment
            let new_assignments: Vec<u32> = (0..n).into_par_iter().map(|i| {
                let v = &vectors_ref[i * DIM..(i + 1) * DIM];
                let mut best_c = 0u32;
                let mut best_dist = f32::MAX;
                for c in 0..N_CLUSTERS {
                    let cv = &centroids_ref[c * DIM..(c + 1) * DIM];
                    let d = l2_squared_f32(v, cv);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c as u32;
                    }
                }
                best_c
            }).collect();

            let changed = new_assignments.iter().zip(assignments.iter())
                .filter(|(a, b)| a != b).count();
            assignments = new_assignments;

            // Parallel centroid update using reduce
            // Split into chunks for parallel accumulation
            let n_threads = 4;
            let chunk_size = (n + n_threads - 1) / n_threads;

            let partial: Vec<(Vec<f32>, Vec<u32>)> = (0..n_threads).into_par_iter().map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                if start >= end {
                    return (vec![0.0f32; N_CLUSTERS * DIM], vec![0u32; N_CLUSTERS]);
                }
                let mut sums = vec![0.0f32; N_CLUSTERS * DIM];
                let mut counts = vec![0u32; N_CLUSTERS];
                for i in start..end {
                    let c = assignments[i] as usize;
                    counts[c] += 1;
                    let v = &vectors_ref[i * DIM..(i + 1) * DIM];
                    let cv = &mut sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cv[d] += v[d];
                    }
                }
                (sums, counts)
            }).collect();

            // Merge partial sums
            let mut new_centroids = vec![0.0f32; N_CLUSTERS * DIM];
            let mut counts = vec![0u32; N_CLUSTERS];
            for (sums, cnts) in &partial {
                for c in 0..N_CLUSTERS {
                    counts[c] += cnts[c];
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    let sv = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cv[d] += sv[d];
                    }
                }
            }

            for c in 0..N_CLUSTERS {
                let cnt = counts[c];
                if cnt > 0 {
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    let inv = 1.0f32 / cnt as f32;
                    for d in 0..DIM {
                        cv[d] *= inv;
                    }
                } else {
                    // keep old centroid
                    new_centroids[c * DIM..(c + 1) * DIM]
                        .copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                }
            }

            centroids = new_centroids;
            eprintln!("  k-means iter {}: {} changed", iter, changed);
            if changed == 0 {
                break;
            }
        }

        // Build inverted lists
        let mut clusters: Vec<Vec<u32>> = vec![Vec::new(); N_CLUSTERS];
        for i in 0..n {
            clusters[assignments[i] as usize].push(i as u32);
        }

        self.centroids = centroids;
        self.clusters = clusters;
        self.index_built_at = n;
        self.index_valid = true;
        eprintln!("IVF index built.");
    }

    fn add_to_index(&mut self, idx: usize) {
        if !self.index_valid || self.centroids.is_empty() {
            return;
        }
        let v = &self.vectors[idx * DIM..(idx + 1) * DIM];
        let mut best_c = 0usize;
        let mut best_dist = f32::MAX;
        for c in 0..N_CLUSTERS {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            let d = l2_squared_f32(v, cv);
            if d < best_dist {
                best_dist = d;
                best_c = c;
            }
        }
        self.clusters[best_c].push(idx as u32);
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n_probe = N_PROBE.min(N_CLUSTERS);

        // Compute distances to all centroids
        let mut centroid_dists: Vec<(f32, usize)> = (0..N_CLUSTERS).map(|c| {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            (l2_squared_f32(query, cv), c)
        }).collect();

        // Partial sort to get top n_probe
        centroid_dists.select_nth_unstable_by(n_probe - 1, |a, b| {
            a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal)
        });

        // Search within probed clusters using max-heap
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for &(_, c) in &centroid_dists[..n_probe] {
            for &vi in &self.clusters[c] {
                let v = self.get_vector(vi as usize);
                let d = l2_squared_f32(query, v);
                if heap.len() < top_k {
                    heap.push(DistId(d, self.ids[vi as usize]));
                    if heap.len() == top_k {
                        worst = heap.peek().unwrap().0;
                    }
                } else if d < worst {
                    heap.pop();
                    heap.push(DistId(d, self.ids[vi as usize]));
                    worst = heap.peek().unwrap().0;
                }
            }
        }

        // into_sorted_vec gives ascending order for max-heap (smallest first)
        heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n = self.n_vectors();
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for i in 0..n {
            let v = self.get_vector(i);
            let d = l2_squared_f32(query, v);
            if heap.len() < top_k {
                heap.push(DistId(d, self.ids[i]));
                if heap.len() == top_k {
                    worst = heap.peek().unwrap().0;
                }
            } else if d < worst {
                heap.pop();
                heap.push(DistId(d, self.ids[i]));
                worst = heap.peek().unwrap().0;
            }
        }

        heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            inner: RwLock::new(DBInner::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut db = self.inner.write();
        let idx = db.n_vectors();
        db.ids.push(id);
        db.vectors.extend_from_slice(&vector);
        db.add_to_index(idx);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut db = self.inner.write();
            let start_idx = db.n_vectors();

            db.ids.reserve(count);
            db.vectors.reserve(count * DIM);

            for (id, vec) in &vectors {
                db.ids.push(*id);
                db.vectors.extend_from_slice(vec);
            }

            if db.index_valid {
                for i in 0..count {
                    db.add_to_index(start_idx + i);
                }
            }
        }

        // Trigger index build when needed
        let should_build = {
            let db = self.inner.read();
            let n = db.n_vectors();
            let built_at = db.index_built_at;
            let valid = db.index_valid;
            n >= N_CLUSTERS && (!valid || built_at < n / 2)
        };

        if should_build {
            let mut db = self.inner.write();
            let n = db.n_vectors();
            let built_at = db.index_built_at;
            let valid = db.index_valid;
            if n >= N_CLUSTERS && (!valid || built_at < n / 2) {
                db.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let db = self.inner.read();
        let top_k = top_k as usize;

        if db.index_valid && db.n_vectors() >= N_CLUSTERS {
            db.search_ivf(vector, top_k)
        } else {
            db.search_brute_force(vector, top_k)
        }
    }
}

use crate::api::*;
use crate::distance::l2_squared_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

// IVF parameters
const DIM: usize = 128;
const N_CLUSTERS: usize = 2048;   // number of IVF centroids
const N_PROBE: usize = 80;        // number of clusters to probe at search time
const KMEANS_ITERS: usize = 8;    // k-means iterations

/// Max-heap entry: keeps k smallest distances
#[derive(Clone, Copy)]
struct DistId(f32, u64);

impl PartialEq for DistId { fn eq(&self, o: &Self) -> bool { self.0 == o.0 } }
impl Eq for DistId {}
impl PartialOrd for DistId {
    fn partial_cmp(&self, o: &Self) -> Option<Ordering> { self.0.partial_cmp(&o.0) }
}
impl Ord for DistId {
    fn cmp(&self, o: &Self) -> Ordering { self.0.partial_cmp(&o.0).unwrap_or(Ordering::Equal) }
}

pub struct VectorDB {
    inner: RwLock<DBInner>,
}

struct DBInner {
    vectors: Vec<f32>,       // flat: n_vectors * DIM
    ids: Vec<u64>,

    centroids: Vec<f32>,     // N_CLUSTERS * DIM
    clusters: Vec<Vec<u32>>, // N_CLUSTERS entries (vector indices)

    index_built_at: usize,
    index_valid: bool,
}

impl DBInner {
    fn new() -> Self {
        DBInner {
            vectors: Vec::new(),
            ids: Vec::new(),
            centroids: Vec::new(),
            clusters: vec![Vec::new(); N_CLUSTERS],
            index_built_at: 0,
            index_valid: false,
        }
    }

    #[inline(always)]
    fn n_vectors(&self) -> usize { self.ids.len() }

    #[inline(always)]
    fn get_vector(&self, idx: usize) -> &[f32] {
        let off = idx * DIM;
        unsafe { self.vectors.get_unchecked(off..off + DIM) }
    }

    /// Build IVF index using mini-batch k-means for speed
    fn build_index(&mut self) {
        let n = self.n_vectors();
        if n < N_CLUSTERS {
            self.index_valid = false;
            return;
        }

        eprintln!("Building IVF index: {} vectors, {} clusters...", n, N_CLUSTERS);

        // Initialize centroids with evenly-spaced samples
        let step = n / N_CLUSTERS;
        let mut centroids = vec![0.0f32; N_CLUSTERS * DIM];
        for c in 0..N_CLUSTERS {
            let src = self.get_vector(c * step);
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(src);
        }

        // Full k-means with parallel assignment
        let mut assignments = vec![0u32; n];

        for iter in 0..KMEANS_ITERS {
            let vectors_ref = &self.vectors;
            let centroids_ref = &centroids;

            // Parallel assignment: each vector finds its nearest centroid
            // Process vectors in blocks to stay cache-friendly
            let new_assignments: Vec<u32> = (0..n).into_par_iter()
                .with_min_len(4096)
                .map(|i| {
                    let v = unsafe { vectors_ref.get_unchecked(i * DIM..(i + 1) * DIM) };
                    let mut best_c = 0u32;
                    let mut best_dist = f32::MAX;
                    let cp = centroids_ref.as_ptr();
                    for c in 0..N_CLUSTERS {
                        let cv = unsafe { std::slice::from_raw_parts(cp.add(c * DIM), DIM) };
                        let d = l2_squared_f32(v, cv);
                        if d < best_dist {
                            best_dist = d;
                            best_c = c as u32;
                        }
                    }
                    best_c
                }).collect();

            let changed = new_assignments.iter().zip(assignments.iter())
                .filter(|(a, b)| a != b).count();
            assignments = new_assignments;

            // Parallel centroid update
            let n_threads = 4;
            let chunk_size = (n + n_threads - 1) / n_threads;

            let partial: Vec<(Vec<f32>, Vec<u32>)> = (0..n_threads).into_par_iter().map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                if start >= end {
                    return (vec![0.0f32; N_CLUSTERS * DIM], vec![0u32; N_CLUSTERS]);
                }
                let mut sums = vec![0.0f32; N_CLUSTERS * DIM];
                let mut counts = vec![0u32; N_CLUSTERS];
                for i in start..end {
                    let c = assignments[i] as usize;
                    counts[c] += 1;
                    let v = unsafe { vectors_ref.get_unchecked(i * DIM..(i + 1) * DIM) };
                    let cv = unsafe { sums.get_unchecked_mut(c * DIM..(c + 1) * DIM) };
                    for d in 0..DIM {
                        cv[d] += v[d];
                    }
                }
                (sums, counts)
            }).collect();

            let mut new_centroids = vec![0.0f32; N_CLUSTERS * DIM];
            let mut counts = vec![0u32; N_CLUSTERS];
            for (sums, cnts) in &partial {
                for c in 0..N_CLUSTERS {
                    counts[c] += cnts[c];
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    let sv = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cv[d] += sv[d];
                    }
                }
            }
            for c in 0..N_CLUSTERS {
                let cnt = counts[c];
                if cnt > 0 {
                    let cv = &mut new_centroids[c * DIM..(c + 1) * DIM];
                    let inv = 1.0f32 / cnt as f32;
                    for d in 0..DIM {
                        cv[d] *= inv;
                    }
                } else {
                    new_centroids[c * DIM..(c + 1) * DIM]
                        .copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                }
            }

            centroids = new_centroids;
            eprintln!("  iter {}: {} changed", iter, changed);
            if changed < n / 200 {
                break;
            }
        }

        // Build inverted lists
        let mut clusters: Vec<Vec<u32>> = vec![Vec::new(); N_CLUSTERS];
        for i in 0..n {
            clusters[assignments[i] as usize].push(i as u32);
        }

        self.centroids = centroids;
        self.clusters = clusters;
        self.index_built_at = n;
        self.index_valid = true;
        eprintln!("IVF index built.");
    }

    fn add_to_index(&mut self, idx: usize) {
        if !self.index_valid || self.centroids.is_empty() {
            return;
        }
        let v = self.get_vector(idx);
        let mut best_c = 0usize;
        let mut best_dist = f32::MAX;
        for c in 0..N_CLUSTERS {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            let d = l2_squared_f32(v, cv);
            if d < best_dist {
                best_dist = d;
                best_c = c;
            }
        }
        self.clusters[best_c].push(idx as u32);
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n_probe = N_PROBE.min(N_CLUSTERS);

        // Find n_probe nearest centroids
        let mut centroid_dists: Vec<(f32, usize)> = (0..N_CLUSTERS).map(|c| {
            let cv = &self.centroids[c * DIM..(c + 1) * DIM];
            (l2_squared_f32(query, cv), c)
        }).collect();

        centroid_dists.select_nth_unstable_by(n_probe - 1, |a, b| {
            a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal)
        });

        // Search probed clusters with max-heap
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for &(_, c) in &centroid_dists[..n_probe] {
            for &vi in &self.clusters[c] {
                let v = self.get_vector(vi as usize);
                let d = l2_squared_f32(query, v);
                if heap.len() < top_k {
                    heap.push(DistId(d, self.ids[vi as usize]));
                    if heap.len() == top_k {
                        worst = heap.peek().unwrap().0;
                    }
                } else if d < worst {
                    heap.pop();
                    heap.push(DistId(d, self.ids[vi as usize]));
                    worst = heap.peek().unwrap().0;
                }
            }
        }

        heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n = self.n_vectors();
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for i in 0..n {
            let v = self.get_vector(i);
            let d = l2_squared_f32(query, v);
            if heap.len() < top_k {
                heap.push(DistId(d, self.ids[i]));
                if heap.len() == top_k {
                    worst = heap.peek().unwrap().0;
                }
            } else if d < worst {
                heap.pop();
                heap.push(DistId(d, self.ids[i]));
                worst = heap.peek().unwrap().0;
            }
        }

        heap.into_sorted_vec()
            .into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();
        VectorDB { inner: RwLock::new(DBInner::new()) }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut db = self.inner.write();
        let idx = db.n_vectors();
        db.ids.push(id);
        db.vectors.extend_from_slice(&vector);
        db.add_to_index(idx);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut db = self.inner.write();
            let start_idx = db.n_vectors();
            db.ids.reserve(count);
            db.vectors.reserve(count * DIM);
            for (id, vec) in &vectors {
                db.ids.push(*id);
                db.vectors.extend_from_slice(vec);
            }
            if db.index_valid {
                for i in 0..count {
                    db.add_to_index(start_idx + i);
                }
            }
        }

        // Build/rebuild index when warranted
        let should_build = {
            let db = self.inner.read();
            let n = db.n_vectors();
            let built_at = db.index_built_at;
            let valid = db.index_valid;
            // Build once after 200k, rebuild if more than doubled
            n >= N_CLUSTERS && (!valid || (built_at < 200_000 && n >= 200_000) || built_at < n / 2)
        };

        if should_build {
            let mut db = self.inner.write();
            let n = db.n_vectors();
            let built_at = db.index_built_at;
            let valid = db.index_valid;
            if n >= N_CLUSTERS && (!valid || (built_at < 200_000 && n >= 200_000) || built_at < n / 2) {
                db.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let db = self.inner.read();
        let top_k = top_k as usize;
        if db.index_valid && db.n_vectors() >= N_CLUSTERS {
            db.search_ivf(vector, top_k)
        } else {
            db.search_brute_force(vector, top_k)
        }
    }
}

