use std::collections::BinaryHeap;
use std::cmp::Ordering;

// IVF parameters
const DIM: usize = 128;
const N_CLUSTERS: usize = 1024;  // centroids
const N_PROBE: usize = 64;       // probe clusters at search
const KMEANS_ITERS: usize = 20;

// Build index once when vectors exceed this threshold
// (the benchmark loads 1M vectors then searches, so we build once at end)
const BUILD_THRESHOLD: usize = 900_000;

/// Max-heap entry (keeps k-nearest = smallest distances)
#[derive(Clone, Copy)]
struct DistId(f32, u64);

impl PartialEq for DistId { fn eq(&self, o: &Self) -> bool { self.0 == o.0 } }
impl Eq for DistId {}
impl PartialOrd for DistId {
    fn partial_cmp(&self, o: &Self) -> Option<Ordering> { self.0.partial_cmp(&o.0) }
}
impl Ord for DistId {
    fn cmp(&self, o: &Self) -> Ordering { self.0.partial_cmp(&o.0).unwrap_or(Ordering::Equal) }
}

pub struct VectorDB {
    inner: RwLock<DBInner>,
}

struct DBInner {
    vectors: Vec<f32>,       // flat: n_vectors * DIM
    ids: Vec<u64>,

    centroids: Vec<f32>,     // N_CLUSTERS * DIM
    clusters: Vec<Vec<u32>>, // N_CLUSTERS entries

    index_built_at: usize,
    index_valid: bool,
}

impl DBInner {
    fn new() -> Self {
        DBInner {
            vectors: Vec::new(),
            ids: Vec::new(),
            centroids: Vec::new(),
            clusters: vec![Vec::new(); N_CLUSTERS],
            index_built_at: 0,
            index_valid: false,
        }
    }

    #[inline(always)]
    fn n_vectors(&self) -> usize { self.ids.len() }

    #[inline(always)]
    fn get_vector(&self, idx: usize) -> &[f32] {
        let off = idx * DIM;
        &self.vectors[off..off + DIM]
    }

    fn build_index(&mut self) {
        let n = self.n_vectors();
        if n < N_CLUSTERS {
            self.index_valid = false;
            return;
        }

        eprintln!("[IVF] Building index: {} vectors, {} clusters", n, N_CLUSTERS);
        let t0 = std::time::Instant::now();

        // Initialize centroids with evenly spaced samples
        let step = n / N_CLUSTERS;
        let mut centroids = vec![0.0f32; N_CLUSTERS * DIM];
        for c in 0..N_CLUSTERS {
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(self.get_vector(c * step));
        }

        let mut assignments = vec![0u32; n];

        for iter in 0..KMEANS_ITERS {
            let vecs = &self.vectors;
            let cents = &centroids;

            // Parallel assignment
            let new_asgn: Vec<u32> = (0..n).into_par_iter()
                .with_min_len(4096)
                .map(|i| {
                    let v = &vecs[i * DIM..(i + 1) * DIM];
                    let mut best_c = 0u32;
                    let mut best_d = f32::MAX;
                    for c in 0..N_CLUSTERS {
                        let d = l2_squared_f32(v, &cents[c * DIM..(c + 1) * DIM]);
                        if d < best_d { best_d = d; best_c = c as u32; }
                    }
                    best_c
                }).collect();

            let changed = new_asgn.iter().zip(&assignments).filter(|(a, b)| a != b).count();
            assignments = new_asgn;

            // Parallel centroid update
            const NT: usize = 4;
            let chunk = (n + NT - 1) / NT;
            let partials: Vec<(Vec<f32>, Vec<u32>)> = (0..NT).into_par_iter().map(|t| {
                let s = t * chunk;
                let e = (s + chunk).min(n);
                let mut sums = vec![0.0f32; N_CLUSTERS * DIM];
                let mut cnts = vec![0u32; N_CLUSTERS];
                for i in s..e {
                    let c = assignments[i] as usize;
                    cnts[c] += 1;
                    let v = &vecs[i * DIM..(i + 1) * DIM];
                    let cv = &mut sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM { cv[d] += v[d]; }
                }
                (sums, cnts)
            }).collect();

            let mut new_cents = vec![0.0f32; N_CLUSTERS * DIM];
            let mut cnts = vec![0u32; N_CLUSTERS];
            for (s, c) in &partials {
                for k in 0..N_CLUSTERS {
                    cnts[k] += c[k];
                    let cv = &mut new_cents[k * DIM..(k + 1) * DIM];
                    let sv = &s[k * DIM..(k + 1) * DIM];
                    for d in 0..DIM { cv[d] += sv[d]; }
                }
            }
            for k in 0..N_CLUSTERS {
                if cnts[k] > 0 {
                    let inv = 1.0 / cnts[k] as f32;
                    let cv = &mut new_cents[k * DIM..(k + 1) * DIM];
                    for d in 0..DIM { cv[d] *= inv; }
                } else {
                    new_cents[k * DIM..(k + 1) * DIM].copy_from_slice(&centroids[k * DIM..(k + 1) * DIM]);
                }
            }
            centroids = new_cents;
            eprintln!("  iter {}: {} changed ({:.1}s)", iter, changed, t0.elapsed().as_secs_f32());
            if changed == 0 { break; }
        }

        // Build inverted lists
        let mut clusters: Vec<Vec<u32>> = vec![Vec::new(); N_CLUSTERS];
        for i in 0..n { clusters[assignments[i] as usize].push(i as u32); }

        self.centroids = centroids;
        self.clusters = clusters;
        self.index_built_at = n;
        self.index_valid = true;
        eprintln!("[IVF] Built in {:.1}s", t0.elapsed().as_secs_f32());
    }

    fn add_to_index(&mut self, idx: usize) {
        if !self.index_valid { return; }
        let v = self.get_vector(idx);
        let mut best_c = 0usize;
        let mut best_d = f32::MAX;
        for c in 0..N_CLUSTERS {
            let d = l2_squared_f32(v, &self.centroids[c * DIM..(c + 1) * DIM]);
            if d < best_d { best_d = d; best_c = c; }
        }
        self.clusters[best_c].push(idx as u32);
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let np = N_PROBE.min(N_CLUSTERS);

        let mut cdists: Vec<(f32, usize)> = (0..N_CLUSTERS).map(|c| {
            (l2_squared_f32(query, &self.centroids[c * DIM..(c + 1) * DIM]), c)
        }).collect();
        cdists.select_nth_unstable_by(np - 1, |a, b| a.0.partial_cmp(&b.0).unwrap_or(Ordering::Equal));

        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for &(_, c) in &cdists[..np] {
            for &vi in &self.clusters[c] {
                let v = self.get_vector(vi as usize);
                let d = l2_squared_f32(query, v);
                if heap.len() < top_k {
                    heap.push(DistId(d, self.ids[vi as usize]));
                    if heap.len() == top_k { worst = heap.peek().unwrap().0; }
                } else if d < worst {
                    heap.pop();
                    heap.push(DistId(d, self.ids[vi as usize]));
                    worst = heap.peek().unwrap().0;
                }
            }
        }

        heap.into_sorted_vec().into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let n = self.n_vectors();
        let mut heap: BinaryHeap<DistId> = BinaryHeap::with_capacity(top_k + 1);
        let mut worst = f32::MAX;

        for i in 0..n {
            let v = self.get_vector(i);
            let d = l2_squared_f32(query, v);
            if heap.len() < top_k {
                heap.push(DistId(d, self.ids[i]));
                if heap.len() == top_k { worst = heap.peek().unwrap().0; }
            } else if d < worst {
                heap.pop();
                heap.push(DistId(d, self.ids[i]));
                worst = heap.peek().unwrap().0;
            }
        }

        heap.into_sorted_vec().into_iter()
            .map(|di| SearchResult { id: di.1, distance: (di.0 as f64).sqrt() })
            .collect()
    }
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new().num_threads(4).build_global().ok();
        VectorDB { inner: RwLock::new(DBInner::new()) }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut db = self.inner.write();
        let idx = db.n_vectors();
        db.ids.push(id);
        db.vectors.extend_from_slice(&vector);
        db.add_to_index(idx);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut db = self.inner.write();
            let start = db.n_vectors();
            db.ids.reserve(count);
            db.vectors.reserve(count * DIM);
            for (id, v) in &vectors {
                db.ids.push(*id);
                db.vectors.extend_from_slice(v);
            }
            // Only add to existing valid index for small increments
            if db.index_valid {
                for i in 0..count { db.add_to_index(start + i); }
            }
        }

        // Build index once we have enough vectors (and haven't built yet, or data doubled)
        let should_build = {
            let db = self.inner.read();
            let n = db.n_vectors();
            !db.index_valid && n >= BUILD_THRESHOLD
        };
        if should_build {
            let mut db = self.inner.write();
            if !db.index_valid && db.n_vectors() >= BUILD_THRESHOLD {
                db.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let db = self.inner.read();
        let k = top_k as usize;
        if db.index_valid { db.search_ivf(vector, k) }
        else { db.search_brute_force(vector, k) }
    }
}

